{"query":"
	fragment repo on Repository {
		id
		name
		owner { login }
		hasIssuesEnabled
		description
		hasWikiEnabled
		viewerPermission
		defaultBranchRef {
			name
		}
	}

	query RepositoryInfo($owner: String!, $name: String!) {
		repository(owner: $owner, name: $name) {
			...repo
			parent {
				...repo
			}
			mergeCommitAllowed
			rebaseMergeAllowed
			squashMergeAllowed
		}
	}","variables":{"name":"taskpull","owner":"iwahbe"}}

{"query":"
	query PullRequestForBranch($owner: String!, $repo: String!, $headRefName: String!, $states: [PullRequestState!]) {
		repository(owner: $owner, name: $repo) {
			pullRequests(headRefName: $headRefName, states: $states, first: 30, orderBy: { field: CREATED_AT, direction: DESC }) {
				nodes {url,id,number,state,baseRefName,headRefName,isCrossRepository,headRepositoryOwner{id,login,...on User{name}}}
			}
			defaultBranchRef { name }
		}
	}","variables":{"headRefName":"recapture-test","owner":"iwahbe","repo":"taskpull","states":["OPEN"]}}

{"query":"
		mutation PullRequestCreate($input: CreatePullRequestInput!) {
			createPullRequest(input: $input) {
				pullRequest {
					id
					url
				}
			}
	}","variables":{"input":{"baseRefName":"main","body":"This is a test PR created to capture GH API traffic for proxy tests. Safe to close.","draft":false,"headRefName":"recapture-test","maintainerCanModify":true,"repositoryId":"R_kgDORru3Uw","title":"Test PR for proxy capture"}}}
